class Solution:
    def punishmentNumber(self, n: int) -> int:
        def can_partition(s, target):
            if not s:
                return target == 0
            for i in range(1, len(s) + 1):
                prefix = int(s[:i])
                if can_partition(s[i:], target - prefix):
                    return True
            return False

        result = 0
        for i in range(1, n + 1):
            square = str(i * i)
            if can_partition(square, i):
                result += i * i
        return result
